  ('pukao-77f8735d-moex-00165', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '聯合國每年公布「人類發展指數」（HumanDevelopmentIndex,HDI），用以衡量各國社會經濟發展 程度的標準。請問該指標納入的健康指標為何？', '["自殺死亡率", "嬰幼兒死亡率", "癌症死亡率", "零歲平均餘命"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
